async (params, browser) => {
  // Open Untappd search
  await browser.open(`https://untappd.com/search?q=${params.query}&type=beer`)

  // Wait for results
  await browser.waitForSelector('.results-container, .beer-item, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('.beer-item, .results-container .beer, [class*="beer-result"]').forEach((el, i) => { if (i < 15) { const nameEl = el.querySelector('.name a, .beer-name a, h3 a'); const breweryEl = el.querySelector('.brewery a, .beer-brewery a'); const ratingEl = el.querySelector('.rating, .num, [class*="rating"]'); const styleEl = el.querySelector('.style, .beer-style'); results.push({ name: nameEl?.textContent?.trim() || '', url: nameEl?.href || '', brewery: breweryEl?.textContent?.trim() || '', rating: ratingEl?.textContent?.trim() || '', style: styleEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
